CREATE DATABASE /*!32312 IF NOT EXISTS*/ `pyhouse` /*!40100 DEFAULT CHARACTER SET utf8mb4 */;

USE `pyhouse`;

DROP TABLE IF EXISTS `config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `config` (
                          `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
                          `name` varchar(100) NOT NULL COMMENT '配置参数名称',
                          `value` varchar(100) DEFAULT NULL COMMENT '配置参数值',
                          `url` varchar(500) DEFAULT NULL COMMENT 'url',
                          PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8 COMMENT='配置文件';

LOCK TABLES `config` WRITE;
/*!40000 ALTER TABLE `config` DISABLE KEYS */;
INSERT INTO `config` VALUES (1,'picture1','upload/picture1.jpg',NULL),(2,'picture2','upload/picture2.jpg',NULL),(3,'picture3','upload/1710903621196.png',NULL);
/*!40000 ALTER TABLE `config` ENABLE KEYS */;
UNLOCK TABLES;


DROP TABLE IF EXISTS `discuss`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `discuss` (
                           `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
                           `addtime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                           `refid` bigint(20) NOT NULL COMMENT '关联表id',
                           `userid` bigint(20) NOT NULL COMMENT '用户id',
                           `avatarurl` longtext COMMENT '头像',
                           `nickname` varchar(200) DEFAULT NULL COMMENT '用户名',
                           `content` longtext NOT NULL COMMENT '评论内容',
                           `reply` longtext COMMENT '回复内容',
                           PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1710903559226 DEFAULT CHARSET=utf8 COMMENT='房屋评论表';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `discuss` WRITE;
/*!40000 ALTER TABLE `discuss` DISABLE KEYS */;
INSERT INTO `discuss` VALUES (1710903559225,'2024-03-20 02:59:19',35,1710903541424,'upload/1710903532641.jpeg','111','<p>66666666666</p>','<p>回复评论</p>');
/*!40000 ALTER TABLE `discuss` ENABLE KEYS */;
UNLOCK TABLES;





DROP TABLE IF EXISTS `news`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `news` (
                        `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
                        `addtime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                        `title` varchar(200) NOT NULL COMMENT '标题',
                        `introduction` longtext COMMENT '简介',
                        `typename` varchar(200) DEFAULT NULL COMMENT '分类名称',
                        `name` varchar(200) DEFAULT NULL COMMENT '发布人',
                        `headportrait` longtext COMMENT '头像',
                        `clicknum` int(11) DEFAULT '0' COMMENT '点击次数',
                        `clicktime` datetime DEFAULT NULL COMMENT '最近点击时间',
                        `thumbsupnum` int(11) DEFAULT '0' COMMENT '赞',
                        `crazilynum` int(11) DEFAULT '0' COMMENT '踩',
                        `storeupnum` int(11) DEFAULT '0' COMMENT '收藏数',
                        `picture` longtext NOT NULL COMMENT '图片',
                        `content` longtext NOT NULL COMMENT '内容',
                        PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1710903655191 DEFAULT CHARSET=utf8 COMMENT='公告信息';
/*!40101 SET character_set_client = @saved_cs_client */;

INSERT INTO `news` (
    `title`, `introduction`, `typename`, `name`, `headportrait`,
    `clicknum`, `clicktime`, `thumbsupnum`, `crazilynum`, `storeupnum`,
    `picture`, `content`
) VALUES
-- 第1-10条
('2025年二手房交易税费新政策解读', '本文详细解读2025年最新二手房交易税费调整政策，帮助购房者了解成本变化。', '行业政策', '房产资讯小编', 'https://example.com/avatar/1.jpg', 1258, '2025-01-15 09:23:45', 236, 12, 89, 'https://example.com/img/1.jpg', '### 2025年二手房交易税费新政策\n1. 契税：首套房90㎡以下减按1%征收，90㎡以上1.5%；二套房统一2%。\n2. 增值税：满2年免征，不满2年按5.6%征收。\n3. 个人所得税：满5年且唯一住房免征，否则按差额20%或全额1%征收。\n\n政策执行时间：2025年1月1日起。'),
('2025年1月全国二手房均价环比上涨0.8%', '国家统计局数据显示，2025年1月全国二手房均价环比上涨0.8%，一线城市涨幅领先。', '市场动态', '数据分析师', 'https://example.com/avatar/2.jpg', 2890, '2025-01-20 14:15:30', 452, 38, 156, 'https://example.com/img/2.jpg', '### 2025年1月二手房市场数据\n- 全国均价：15680元/㎡，环比+0.8%，同比+2.3%。\n- 一线城市：北京+1.2%、上海+1.5%、广州+0.9%、深圳+1.1%。\n- 二线城市：整体涨幅0.6%，成都、杭州、武汉涨幅靠前。\n- 成交量：全国共成交28.5万套，环比+5.2%。'),
('优质学区房推荐：海淀区核心地段三居室', '推荐海淀区中关村学区房，三居室，满五唯一，配套成熟，对口重点小学。', '房源资讯', '置业顾问', 'https://example.com/avatar/3.jpg', 3560, '2025-01-10 10:05:12', 689, 25, 210, 'https://example.com/img/3.jpg', '### 房源详情\n- 位置：北京市海淀区中关村南大街\n- 户型：3室2厅2卫，128㎡\n- 价格：1280万（单价99980元/㎡）\n- 产权：70年住宅，满五唯一\n- 配套：对口中关村三小，步行5分钟到地铁4号线，周边商超、医院齐全。'),
('二手房贷款审批流程及注意事项', '详解二手房商业贷款和公积金贷款的审批流程、所需材料及常见问题。', '购房指南', '金融顾问', 'https://example.com/avatar/4.jpg', 1895, '2025-01-08 16:40:22', 328, 18, 105, 'https://example.com/img/4.jpg', '### 二手房贷款审批流程\n#### 商业贷款\n1. 提交申请：身份证、户口本、结婚证、购房合同、收入证明等。\n2. 银行审核：征信查询、资质审核，约3-5个工作日。\n3. 评估房产：第三方评估机构上门评估，约1-2个工作日。\n4. 审批通过：签订贷款合同，办理抵押登记。\n5. 放款：抵押完成后，银行放款至卖方账户。\n\n#### 注意事项\n- 征信逾期次数不超过3次，否则影响审批。\n- 收入证明需覆盖月供的2倍以上。'),
('老房翻新装修技巧：低成本高效果', '分享老二手房翻新装修的实用技巧，控制成本的同时提升居住体验。', '装修技巧', '装修设计师', 'https://example.com/avatar/5.jpg', 1672, '2025-01-12 11:30:45', 298, 15, 98, 'https://example.com/img/5.jpg', '### 老房翻新技巧\n1. 墙面处理：无需全铲，局部修补后刷环保乳胶漆即可，节省成本。\n2. 水电改造：重点检查老化线路，厨卫水电必须重做，其他区域可保留。\n3. 空间利用：定制收纳柜，利用阳台、飘窗增加储物空间。\n4. 材料选择：性价比优先，瓷砖选广东砖，地板选强化复合地板。\n5. 配色：浅色系为主，提升空间通透感。'),
('租房避坑指南：这些条款一定要注意', '租房时容易踩坑的条款和细节，帮助租客维护自身权益。', '租房须知', '法务专员', 'https://example.com/avatar/6.jpg', 1450, '2025-01-18 09:10:15', 276, 22, 85, 'https://example.com/img/6.jpg', '### 租房避坑要点\n1. 合同条款：明确租金支付方式、押金退还条件、违约责任。\n2. 房屋状况：入住前拍照留证，记录家电家具损坏情况。\n3. 中介费：明确中介费金额和支付时间，避免隐形收费。\n4. 房东资质：核实房产证和身份证，确认房东身份。\n5. 解约条款：明确提前解约的条件和违约金比例。'),
('2025年二线城市房价走势预测', '分析2025年二线城市房价走势，哪些城市有上涨潜力？', '房价走势', '房产分析师', 'https://example.com/avatar/7.jpg', 2180, '2025-01-22 15:20:30', 389, 28, 126, 'https://example.com/img/7.jpg', '### 2025年二线城市房价预测\n#### 上涨潜力城市\n- 成都：人口流入持续，产业升级，预计涨幅3-5%。\n- 杭州：数字经济带动，亚运会后配套完善，预计涨幅2-4%。\n- 武汉：长江经济带核心，基建投入大，预计涨幅1-3%。\n#### 平稳城市\n- 西安、重庆、长沙：供需平衡，房价保持平稳。\n#### 小幅下跌城市\n- 天津、哈尔滨：人口流出，预计跌幅1-2%。'),
('浦东新区购房区域解读：哪个板块值得入手？', '详细解读上海浦东新区各板块的房价、配套、发展潜力，推荐置业板块。', '区域解读', '本地房产专家', 'https://example.com/avatar/8.jpg', 2650, '2025-01-16 13:45:18', 428, 32, 145, 'https://example.com/img/8.jpg', '### 浦东新区板块分析\n1. 陆家嘴：核心商务区，房价高，适合投资，均价18万/㎡。\n2. 张江科学城：科创产业聚集，刚需改善为主，均价8.5万/㎡。\n3. 临港新片区：政策扶持，价格低洼，均价3.2万/㎡，长期潜力大。\n4. 金桥：配套成熟，宜居性高，均价7.8万/㎡。\n5. 唐镇：地铁沿线，刚需首选，均价6.5万/㎡。'),
('二手房交易流程全攻略：从看房到过户', '完整梳理二手房交易的全流程，包括看房、议价、签约、过户等环节。', '购房指南', '资深置业顾问', 'https://example.com/avatar/9.jpg', 3120, '2025-01-05 10:20:45', 589, 45, 189, 'https://example.com/img/9.jpg', '### 二手房交易全流程\n1. 看房选房：确定需求，实地看房，对比多套房源。\n2. 价格谈判：通过中介和房东议价，确定成交价格。\n3. 签订合同：签订购房合同，支付定金（一般为总房款的1-5%）。\n4. 办理贷款：提交贷款申请，银行审核评估。\n5. 网签备案：到房管局办理网签，避免一房多卖。\n6. 缴纳税费：根据政策缴纳契税、增值税、个税等。\n7. 过户领证：办理产权过户，领取新房产证。\n8. 交房验房：验收房屋，交接水电燃气，支付尾款。'),
('装修预算控制：100㎡二手房装修多少钱？', '详细拆解100㎡二手房装修的各项费用，帮助业主控制预算。', '装修技巧', '预算规划师', 'https://example.com/avatar/10.jpg', 1980, '2025-01-09 14:30:25', 356, 20, 112, 'https://example.com/img/10.jpg', '### 100㎡二手房装修预算\n#### 基础装修（硬装）\n- 拆改：5000-8000元\n- 水电改造：8000-12000元\n- 墙面地面：20000-30000元\n- 厨卫装修：15000-25000元\n- 门窗更换：8000-15000元\n#### 软装家具\n- 家具：20000-50000元\n- 家电：15000-30000元\n- 软装（窗帘、灯具等）：5000-10000元\n#### 总预算：简装8-12万，中装12-18万，精装18万以上。'),

-- 第11-20条（省略部分重复逻辑，保持数据多样性）
('2025年公积金贷款额度上调：最高可贷120万', '多地调整公积金贷款政策，最高额度上调至120万，降低购房压力。', '行业政策', '公积金中心专员', 'https://example.com/avatar/11.jpg', 2350, '2025-01-25 09:50:30', 412, 25, 138, 'https://example.com/img/11.jpg', '### 公积金贷款额度调整\n1. 一线城市：北京、上海、广州、深圳，单人最高可贷80万，夫妻双方最高120万。\n2. 二线城市：成都、杭州、武汉等，单人最高60万，夫妻双方最高90万。\n3. 调整时间：2025年2月1日起执行。\n4. 申请条件：连续缴纳公积金6个月以上，无逾期记录。'),
('春节后二手房成交量回升：刚需客户集中入市', '2025年春节后第一周，全国二手房成交量环比上涨15%，刚需客户集中入市。', '市场动态', '市场研究员', 'https://example.com/avatar/12.jpg', 1890, '2025-01-28 11:15:45', 325, 18, 98, 'https://example.com/img/12.jpg', '### 春节后市场数据\n- 成交量：全国成交4.2万套，环比+15%，同比+8%。\n- 客户类型：刚需客户占比65%，改善型客户占比25%，投资客户占比10%。\n- 价格：议价空间缩小，房东报价坚挺，实际成交价环比上涨0.5%。\n- 热门户型：90-120㎡三居室，占成交总量的45%。'),
('朝阳区精装两居室：拎包入住，近地铁', '朝阳区望京板块精装两居室，满二唯一，近地铁14号线，拎包入住。', '房源资讯', '房产经纪人', 'https://example.com/avatar/13.jpg', 3280, '2025-01-14 16:20:15', 568, 30, 178, 'https://example.com/img/13.jpg', '### 房源信息\n- 位置：北京市朝阳区望京西园\n- 户型：2室1厅1卫，89㎡\n- 价格：780万（单价87640元/㎡）\n- 装修：精装修，家具家电齐全，拎包入住\n- 配套：步行8分钟到地铁14号线望京站，周边商场、超市、医院齐全。'),
('二手房避坑：这些房源千万不要买', '盘点二手房交易中需要避开的坑，哪些房源存在风险？', '购房指南', '房产律师', 'https://example.com/avatar/14.jpg', 2850, '2025-01-19 10:30:20', 489, 35, 165, 'https://example.com/img/14.jpg', '### 高风险房源类型\n1. 查封房：产权被法院查封，无法过户，切勿购买。\n2. 抵押房：未解除抵押的房源，需确认房东有能力解押。\n3. 共有房：多人共有产权，需所有共有人签字同意出售。\n4. 小产权房：无房产证，不受法律保护，无法交易。\n5. 违规加盖房：存在违建，可能被拆除，无法过户。'),
('旧房改造：卫生间防水怎么做才不漏水？', '详解二手房卫生间防水施工流程和注意事项，避免漏水问题。', '装修技巧', '防水工程师', 'https://example.com/avatar/15.jpg', 1780, '2025-01-21 15:40:30', 312, 16, 105, 'https://example.com/img/15.jpg', '### 卫生间防水施工\n1. 基层处理：清理地面，修补裂缝，保证平整干燥。\n2. 涂刷防水涂料：选用聚合物水泥基防水涂料，涂刷2-3遍，厚度≥1.5mm。\n3. 重点部位：墙角、管道根部做附加层，高度≥30cm。\n4. 闭水试验：防水完成后，蓄水24小时，检查楼下是否漏水。\n5. 保护层：闭水试验合格后，做水泥砂浆保护层。'),
('合租租房攻略：如何选择靠谱的室友？', '合租租房时，如何选择靠谱的室友，避免矛盾和纠纷？', '租房须知', '租房顾问', 'https://example.com/avatar/16.jpg', 1560, '2025-01-23 09:15:10', 289, 20, 89, 'https://example.com/img/16.jpg', '### 合租室友选择技巧\n1. 背景核实：了解室友的职业、作息时间、生活习惯。\n2. 沟通确认：提前沟通卫生习惯、水电费分摊、访客政策等。\n3. 签订协议：签订合租协议，明确各自的权利和义务。\n4. 押金处理：明确押金的缴纳和退还方式，避免纠纷。\n5. 紧急联系人：留存室友的紧急联系人信息，以备不时之需。'),
('2025年房贷利率走势：预计小幅下调', '专家预测2025年房贷利率将小幅下调，首套房利率或降至3.8%。', '房价走势', '金融分析师', 'https://example.com/avatar/17.jpg', 2450, '2025-01-26 14:25:45', 432, 28, 142, 'https://example.com/img/17.jpg', '### 房贷利率预测\n1. 首套房商业贷款利率：预计从当前的4.0%下调至3.8-3.9%。\n2. 二套房商业贷款利率：预计从4.8%下调至4.6-4.7%。\n3. 公积金贷款利率：保持稳定，首套房3.25%，二套房3.75%。\n4. 调整时间：预计2025年第二季度落地。'),
('杭州市西湖区购房解读：学区房vs非学区房', '对比杭州市西湖区学区房和非学区房的价格、涨幅、流动性。', '区域解读', '杭州房产专家', 'https://example.com/avatar/18.jpg', 2180, '2025-01-17 11:50:20', 378, 25, 120, 'https://example.com/img/18.jpg', '### 西湖区房产分析\n1. 学区房：均价9.5万/㎡，涨幅稳定，每年2-3%，流动性好。\n2. 非学区房：均价6.8万/㎡，涨幅1-2%，流动性一般。\n3. 推荐板块：学军小学学区、文三街小学学区，保值性强。\n4. 注意事项：学区政策可能调整，需提前核实。'),
('二手房税费计算器：一键算出你的购房成本', '推荐实用的二手房税费计算器，输入房源信息即可一键算出总购房成本。', '购房指南', '工具开发师', 'https://example.com/avatar/19.jpg', 1980, '2025-01-07 13:10:35', 345, 18, 108, 'https://example.com/img/19.jpg', '### 二手房税费计算器使用指南\n1. 输入信息：房源面积、成交价格、是否满五唯一、是否首套房。\n2. 计算项目：契税、增值税、个人所得税、印花税、中介费等。\n3. 工具地址：https://example.com/tax-calculator\n4. 注意事项：计算器结果仅供参考，实际税费以房管局核算为准。'),
('客厅装修技巧：小户型如何显大？', '二手房小户型客厅装修技巧，通过布局和软装让客厅显大。', '装修技巧', '软装设计师', 'https://example.com/avatar/20.jpg', 1650, '2025-01-11 15:15:40', 298, 14, 95, 'https://example.com/img/20.jpg', '### 小户型客厅装修\n1. 布局：采用开放式布局，打通客厅和餐厅，增加空间感。\n2. 家具：选择小巧的多功能家具，如折叠餐桌、收纳沙发。\n3. 配色：浅色系墙面和地板，增加通透感。\n4. 灯光：采用筒灯+射灯，避免主灯压抑，增加层次感。\n5. 镜子：在墙面安装镜子，反射光线，视觉上扩大空间。'),

